sql:
SELECT judge_name, experience
FROM judges
ORDER BY experience DESC;

external_knowledge:
- Average score is calculated by averaging the sum of affirmative and negative scores for each debate; 
- Team performance is measured by the number of debates participated in and the average score; 
- Judge feedback is an evaluation of team performance given by the judges; 
- Teams are ranked based on their performance to evaluate their strengths and weaknesses.

sql:
SELECT COUNT(debate_id) AS total_debates
FROM debates
WHERE tournament_id = 1;

SELECT MAX(score) AS highest_score
FROM judge_scores
WHERE criteria_id = 1;

SELECT tournament_name
FROM tournaments
ORDER BY start_date, tournament_name;

SELECT judge_name
FROM judges
WHERE judge_id IN (SELECT judge_id FROM judge_feedback);

SELECT judge_name
FROM judges
WHERE judge_id IN (
  SELECT DISTINCT judge_id
  FROM judge_feedback
);

external_knowledge:
; Ranking implies that the order matters; 
; The word 'top 3' refers to the highest ranked 3 judges; 
; 'Winning teams' refers to the team that wins the debate, i.e., the team with the higher score; 
; A tournament is a series of debates between teams, with one or more judges scoring each debate.

sql:
SELECT judge_name
FROM judges
WHERE judge_id IN (SELECT judge_id FROM scores);
